import{_ as t,o,c as r,a2 as a}from"./chunks/framework.il0noOp3.js";const p=JSON.parse('{"title":"Differences from Azure Resource Inventory (ARI)","description":"What AzureScout changed, added, and removed compared to the original ARI project.","frontmatter":{"description":"What AzureScout changed, added, and removed compared to the original ARI project."},"headers":[],"relativePath":"ari-differences.md","filePath":"ari-differences.md"}'),n={name:"ari-differences.md"};function s(i,e,d,c,l,u){return o(),r("div",null,[...e[0]||(e[0]=[a(`<h1 id="differences-from-azure-resource-inventory-ari" tabindex="-1">Differences from Azure Resource Inventory (ARI) <a class="header-anchor" href="#differences-from-azure-resource-inventory-ari" aria-label="Permalink to &quot;Differences from Azure Resource Inventory (ARI)&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>AzureScout is a fork of <a href="https://github.com/microsoft/ARI" target="_blank" rel="noreferrer">Azure Resource Inventory (ARI)</a> v3.6.11, created by <a href="https://github.com/claudiomerola" target="_blank" rel="noreferrer">Claudio Merola</a> and <a href="https://github.com/intfrr" target="_blank" rel="noreferrer">Renato Gregio</a> at Microsoft. Everything listed on this page describes <em>how AzureScout diverges from ARI</em> — not a criticism of the original project. We encourage you to evaluate both projects and choose the one that fits your needs.</p></div><h2 id="what-azurescout-inherits-from-ari" tabindex="-1">What AzureScout Inherits from ARI <a class="header-anchor" href="#what-azurescout-inherits-from-ari" aria-label="Permalink to &quot;What AzureScout Inherits from ARI&quot;">​</a></h2><p>AzureScout would not exist without the foundation laid by ARI. The following core capabilities come directly from the original project:</p><table tabindex="0"><thead><tr><th>Area</th><th>What We Inherited</th></tr></thead><tbody><tr><td><strong>ARM Resource Extraction</strong></td><td>The fundamental pattern of using Azure Resource Graph and ARM APIs to enumerate resources across subscriptions.</td></tr><tr><td><strong>Draw.io Diagram Engine</strong></td><td>All network topology diagram generation — VNets, subnets, peerings, NSGs, load balancers, and resource layout logic.</td></tr><tr><td><strong>Excel Report Pipeline</strong></td><td>The ImportExcel-based pipeline that turns resource data into formatted <code>.xlsx</code> workbooks with conditional formatting.</td></tr><tr><td><strong>171 ARM Resource Modules</strong></td><td>Every inventory module in <code>Modules/Public/InventoryModules/</code> descends from ARI&#39;s original module set. AzureScout has added new modules and enhanced existing ones, but the pattern and many files trace back to ARI.</td></tr><tr><td><strong>Orchestration Pattern</strong></td><td>The extraction → processing → reporting three-phase orchestration that powers the main pipeline.</td></tr><tr><td><strong>Automation Account Mode</strong></td><td>The concept of running inside an Azure Automation Account with a Managed Identity (though AzureScout has not yet documented or validated this path — see <a href="./roadmap.html">roadmap</a>).</td></tr></tbody></table><h2 id="renamed-identifiers" tabindex="-1">Renamed Identifiers <a class="header-anchor" href="#renamed-identifiers" aria-label="Permalink to &quot;Renamed Identifiers&quot;">​</a></h2><p>The most visible change is the rebranding from ARI to AzureScout. This affects every public-facing name in the module.</p><table tabindex="0"><thead><tr><th>What</th><th>ARI Name</th><th>AzureScout Name</th></tr></thead><tbody><tr><td>PowerShell Module</td><td><code>AzureResourceInventory</code></td><td><code>AzureScout</code></td></tr><tr><td>Main Entry Point</td><td><code>Invoke-ARI</code></td><td><code>Invoke-AzureScout</code></td></tr><tr><td>Exported Function Prefix</td><td><code>*-ARI*</code></td><td><code>*-AZSC*</code></td></tr><tr><td>Internal Function Prefix</td><td><code>*-ARI*</code></td><td><code>*-AZSC*</code></td></tr><tr><td>Module Manifest</td><td><code>AzureResourceInventory.psd1</code></td><td><code>AzureScout.psd1</code></td></tr><tr><td>Root Module File</td><td><code>AzureResourceInventory.psm1</code></td><td><code>AzureScout.psm1</code></td></tr></tbody></table><p>All function definitions inside the <code>.ps1</code> files have been renamed to <code>AZSC</code>, but many <strong>file names on disk</strong> still use an intermediate <code>AZTI</code> prefix (e.g., <code>Start-AZTIAdvisoryJob.ps1</code> contains <code>function Start-AZSCAdvisoryJob</code>). Renaming the file names is tracked as tech debt.</p><h2 id="new-capabilities" tabindex="-1">New Capabilities <a class="header-anchor" href="#new-capabilities" aria-label="Permalink to &quot;New Capabilities&quot;">​</a></h2><p>These features do not exist in ARI v3.6.11 and were built specifically for AzureScout.</p><h3 id="entra-id-inventory-15-modules" tabindex="-1">Entra ID Inventory (15 Modules) <a class="header-anchor" href="#entra-id-inventory-15-modules" aria-label="Permalink to &quot;Entra ID Inventory (15 Modules)&quot;">​</a></h3><p>ARI focuses exclusively on ARM resources. AzureScout adds 15 Microsoft Graph-based modules that inventory Entra ID (Azure AD) objects:</p><ul><li>Users, Groups, Service Principals, App Registrations</li><li>Conditional Access Policies, Named Locations</li><li>Administrative Units, Directory Roles, Role Assignments</li><li>Identity Providers, Security Defaults</li><li>Managed Identities, Enterprise Applications</li><li>Authentication Methods, Password Policies</li></ul><p>These are extracted via <code>Start-AZSCEntraExtraction</code> using a dedicated Graph API token.</p><h3 id="permission-audit-permissionaudit" tabindex="-1">Permission Audit (<code>-PermissionAudit</code>) <a class="header-anchor" href="#permission-audit-permissionaudit" aria-label="Permalink to &quot;Permission Audit (\`-PermissionAudit\`)&quot;">​</a></h3><p>A pre-flight capability that checks whether the running identity has the ARM and Graph permissions needed for a complete inventory <em>before</em> starting extraction.</p><ul><li><code>-PermissionAudit</code> — checks ARM permissions only (default)</li><li><code>-PermissionAudit -Scope All</code> — checks both ARM and Graph permissions</li><li>Outputs results to Console, Markdown, AsciiDoc, or JSON</li></ul><h3 id="execution-scope-scope" tabindex="-1">Execution Scope (<code>-Scope</code>) <a class="header-anchor" href="#execution-scope-scope" aria-label="Permalink to &quot;Execution Scope (\`-Scope\`)&quot;">​</a></h3><p>ARI always inventories ARM resources across every subscription the identity can see. AzureScout adds a <code>-Scope</code> parameter that controls <em>what types of objects</em> are inventoried:</p><ul><li><code>ArmOnly</code> (default) — ARM resources only, same scope as ARI</li><li><code>EntraOnly</code> — Entra ID (Azure AD) objects only, skips ARM</li><li><code>All</code> — both ARM resources and Entra ID objects</li></ul><p>This is separate from the <code>-SubscriptionID</code> parameter (inherited from ARI) that targets a specific subscription.</p><h3 id="multi-format-output-outputformat" tabindex="-1">Multi-Format Output (<code>-OutputFormat</code>) <a class="header-anchor" href="#multi-format-output-outputformat" aria-label="Permalink to &quot;Multi-Format Output (\`-OutputFormat\`)&quot;">​</a></h3><p>ARI outputs Excel (<code>.xlsx</code>) and Draw.io (<code>.drawio</code>) files. AzureScout adds:</p><ul><li><strong>JSON</strong> (<code>-OutputFormat JSON</code>) — raw cache data as <code>.json</code> for programmatic consumption</li><li><strong>Markdown</strong> (<code>-OutputFormat Markdown</code> or <code>-OutputFormat MD</code>) — GitHub-Flavored Markdown tables</li><li><strong>AsciiDoc</strong> (<code>-OutputFormat AsciiDoc</code> or <code>-OutputFormat Adoc</code>) — Antora/Confluence-compatible AsciiDoc tables</li><li><strong>All</strong> (<code>-OutputFormat All</code>) — every format at once</li></ul><h3 id="category-filtering-category" tabindex="-1">Category Filtering (<code>-Category</code>) <a class="header-anchor" href="#category-filtering-category" aria-label="Permalink to &quot;Category Filtering (\`-Category\`)&quot;">​</a></h3><p>Lets you limit extraction and reporting to specific Azure resource categories:</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-AzureScout</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Category Compute</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">,</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Networking</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Supports both short folder names (<code>Compute</code>) and long Azure portal names (<code>AI + machine learning</code>). Modules declare their category via a <code>.CATEGORY</code> comment header, enabling cross-category placement.</p><h3 id="specialized-excel-tabs" tabindex="-1">Specialized Excel Tabs <a class="header-anchor" href="#specialized-excel-tabs" aria-label="Permalink to &quot;Specialized Excel Tabs&quot;">​</a></h3><p>AzureScout adds purpose-built Excel worksheets that aggregate data across resource types:</p><ul><li><strong>Cost Management</strong> — VM cost estimates, Arc ESU costs, reservation recommendations</li><li><strong>Security Overview</strong> — Defender secure score, high/critical assessments, active alerts, plan pricing</li><li><strong>Azure Update Manager</strong> — Patch compliance across VMs and Arc servers</li><li><strong>Azure Monitor</strong> — Action groups, DCRs, DCEs, App Insights, alert rules, autoscale settings</li></ul><h3 id="resource-enrichment" tabindex="-1">Resource Enrichment <a class="header-anchor" href="#resource-enrichment" aria-label="Permalink to &quot;Resource Enrichment&quot;">​</a></h3><p>Virtual Machine and Arc Server modules now pull supplementary data from multiple APIs:</p><ul><li><strong>Azure Monitor Metrics</strong> — 7-day average CPU and memory usage</li><li><strong>Azure Site Recovery</strong> — DR replication status, target region, replication health</li><li><strong>Cost Management</strong> — Estimated monthly cost (USD)</li><li><strong>PolicyInsights</strong> — Policy assignment count and compliance state (Arc)</li></ul><h3 id="dependency-bootstrap" tabindex="-1">Dependency Bootstrap <a class="header-anchor" href="#dependency-bootstrap" aria-label="Permalink to &quot;Dependency Bootstrap&quot;">​</a></h3><p>ARI requires modules to be pre-installed (declared in <code>RequiredModules</code>). AzureScout auto-installs missing dependencies on first import:</p><ul><li><code>ImportExcel</code>, <code>Az.Accounts</code>, <code>Az.ResourceGraph</code>, <code>Az.Storage</code>, <code>Az.Compute</code>, <code>Az.Authorization</code>, <code>Az.Resources</code></li></ul><h2 id="structural-changes" tabindex="-1">Structural Changes <a class="header-anchor" href="#structural-changes" aria-label="Permalink to &quot;Structural Changes&quot;">​</a></h2><h3 id="documentation" tabindex="-1">Documentation <a class="header-anchor" href="#documentation" aria-label="Permalink to &quot;Documentation&quot;">​</a></h3><table tabindex="0"><thead><tr><th>ARI</th><th>AzureScout</th></tr></thead><tbody><tr><td>README-only docs</td><td>MkDocs Material documentation site (<code>docs/</code> folder) with navigation, search, and cross-references</td></tr><tr><td>No API/architecture docs</td><td>Dedicated pages for category filtering, coverage tables, category-to-folder mapping</td></tr><tr><td>Inline examples only</td><td>4 structured <code>.EXAMPLE</code> blocks on <code>Invoke-AzureScout</code></td></tr></tbody></table><h3 id="testing" tabindex="-1">Testing <a class="header-anchor" href="#testing" aria-label="Permalink to &quot;Testing&quot;">​</a></h3><table tabindex="0"><thead><tr><th>ARI</th><th>AzureScout</th></tr></thead><tbody><tr><td>No test suite</td><td>25+ Pester test files covering public functions, private functions, inventory modules, output formats, and category filtering</td></tr><tr><td>No synthetic data</td><td><code>New-SyntheticSampleReport.ps1</code> generates test data for offline validation</td></tr></tbody></table><h3 id="folder-reorganization" tabindex="-1">Folder Reorganization <a class="header-anchor" href="#folder-reorganization" aria-label="Permalink to &quot;Folder Reorganization&quot;">​</a></h3><p>ARI&#39;s <code>Modules/Private/</code> uses numbered folders (<code>1.ExtractionFunctions/</code>, <code>2.ProcessingFunctions/</code>, etc.). AzureScout replaces these with descriptive names:</p><table tabindex="0"><thead><tr><th>ARI Path</th><th>AzureScout Path</th></tr></thead><tbody><tr><td><code>Modules/Private/1.ExtractionFunctions/</code></td><td><code>Modules/Private/Extraction/</code></td></tr><tr><td><code>Modules/Private/2.ProcessingFunctions/</code></td><td><code>Modules/Private/Processing/</code></td></tr><tr><td><code>Modules/Private/3.ReportingFunctions/</code></td><td><code>Modules/Private/Reporting/</code></td></tr><tr><td><code>Modules/Private/4.RAMPFunctions/</code></td><td><em>(removed)</em></td></tr></tbody></table><h2 id="removed-from-ari" tabindex="-1">Removed from ARI <a class="header-anchor" href="#removed-from-ari" aria-label="Permalink to &quot;Removed from ARI&quot;">​</a></h2><p>The following ARI features were intentionally removed:</p><table tabindex="0"><thead><tr><th>Feature</th><th>Reason</th></tr></thead><tbody><tr><td><strong>RAMP Functions</strong></td><td><code>Invoke-AzureRAMPInventory</code> and the <code>4.RAMPFunctions/</code> folder were removed. RAMP (Risk Assessment &amp; Mitigation Program) is an internal Microsoft program not broadly applicable.</td></tr><tr><td><strong>Auto-Update Logic</strong></td><td>ARI calls <code>Update-Module</code> to self-update. AzureScout removes this — module updates should be a conscious decision by the operator, not automatic.</td></tr><tr><td><strong>Remove-ARIExcelProcess</strong></td><td>ARI included a function that kills Excel processes to prevent file-lock issues. AzureScout removes this aggressive behavior.</td></tr><tr><td><strong>RequiredModules hard dependency</strong></td><td>Replaced with runtime bootstrap (see <a href="#dependency-bootstrap">Dependency Bootstrap</a>).</td></tr></tbody></table><h2 id="not-yet-in-azurescout" tabindex="-1">Not Yet in AzureScout <a class="header-anchor" href="#not-yet-in-azurescout" aria-label="Permalink to &quot;Not Yet in AzureScout&quot;">​</a></h2><p>These ARI features or ecosystem elements have not been ported or replicated:</p><table tabindex="0"><thead><tr><th>Feature</th><th>Status</th></tr></thead><tbody><tr><td><strong>GitHub Actions CI</strong></td><td>ARI has CI workflows for automated testing and publishing. AzureScout does not yet have CI — tracked in the project roadmap.</td></tr><tr><td><strong>PSGallery Publishing</strong></td><td>ARI is published to the PowerShell Gallery. AzureScout is GitHub-only for now.</td></tr><tr><td><strong>Automation Account Documentation</strong></td><td>ARI has an 8-step guide for running in Azure Automation. AzureScout has the plumbing but no docs — tracked as <a href="https://github.com/thisismydemo/azure-scout/issues/32" target="_blank" rel="noreferrer">Issue #32</a>.</td></tr><tr><td><strong>Containerized Execution</strong></td><td>ARI documents Docker-based execution. AzureScout has not validated container support.</td></tr></tbody></table><h2 id="version-lineage" tabindex="-1">Version Lineage <a class="header-anchor" href="#version-lineage" aria-label="Permalink to &quot;Version Lineage&quot;">​</a></h2><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ARI v3.6.11 (microsoft/ARI)</span></span>
<span class="line"><span>  └── Fork ──→ AzureScout v1.0.0 (thisismydemo/azure-scout)</span></span>
<span class="line"><span>                  ├── Rebranding (ARI → AZSC function prefix)</span></span>
<span class="line"><span>                  ├── +15 Entra ID modules</span></span>
<span class="line"><span>                  ├── +30 new ARM modules (Phases 7–17)</span></span>
<span class="line"><span>                  ├── Permission Audit system</span></span>
<span class="line"><span>                  ├── Multi-format output (JSON, Markdown, AsciiDoc)</span></span>
<span class="line"><span>                  ├── Category filtering</span></span>
<span class="line"><span>                  ├── Specialized Excel tabs</span></span>
<span class="line"><span>                  ├── Resource enrichment (metrics, DR, cost)</span></span>
<span class="line"><span>                  ├── MkDocs Material documentation</span></span>
<span class="line"><span>                  └── Pester test suite</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><h2 id="further-reading" tabindex="-1">Further Reading <a class="header-anchor" href="#further-reading" aria-label="Permalink to &quot;Further Reading&quot;">​</a></h2><ul><li><a href="./credits.html">Credits &amp; Attribution</a> — full list of original authors and contributors</li><li><a href="./">AzureScout Documentation Home</a></li><li><a href="https://github.com/microsoft/ARI" target="_blank" rel="noreferrer">ARI on GitHub</a> — the original project</li><li><a href="https://github.com/thisismydemo/azure-scout" target="_blank" rel="noreferrer">AzureScout on GitHub</a> — this fork</li></ul>`,56)])])}const m=t(n,[["render",s]]);export{p as __pageData,m as default};
